CREATE TABLE tickets (
  event_id INT PRIMARY KEY,
  event_name VARCHAR(80),
  seats_available INT
);

INSERT INTO tickets VALUES
  (1, 'Concert Night',   10),
  (2, 'Tech Conference', 50),
  (3, 'Art Exhibition',   5);

-- Transaction A: User 1 tries to book 3 seats for event 1
-- BEGIN; UPDATE tickets SET seats_available = seats_available - 3 WHERE event_id = 1; COMMIT;

-- Transaction B: User 2 simultaneously tries to book 2 seats for event 1
-- BEGIN; UPDATE tickets SET seats_available = seats_available - 2 WHERE event_id = 1; COMMIT;

-- Run them sequentially here to simulate the end state
BEGIN;
  UPDATE tickets SET seats_available = seats_available - 3 WHERE event_id = 1;
COMMIT;

BEGIN;
  UPDATE tickets SET seats_available = seats_available - 2 WHERE event_id = 1;
COMMIT;

SELECT * FROM tickets;

CREATE TABLE wallet (
  user_id INT PRIMARY KEY,
  username VARCHAR(50),
  balance DECIMAL(10,2),
  CONSTRAINT chk_balance CHECK (balance >= 0)
);

INSERT INTO wallet VALUES
  (1, 'alice', 200.00),
  (2, 'bob',   50.00);

-- Transaction 1: Valid transfer — alice sends 80 to bob
BEGIN;
  UPDATE wallet SET balance = balance - 80 WHERE user_id = 1;
  UPDATE wallet SET balance = balance + 80 WHERE user_id = 2;
COMMIT;

SELECT user_id, username, balance FROM wallet;

-- Transaction 2: Invalid transfer — bob tries to send 200 (only has 130.00)
-- The CHECK constraint will prevent balance going negative
BEGIN;
  UPDATE wallet SET balance = balance - 200 WHERE user_id = 2;
  UPDATE wallet SET balance = balance + 200 WHERE user_id = 1;
-- The first UPDATE violates CHECK(balance >= 0), database will error and rollback
ROLLBACK;

SELECT user_id, username, balance FROM wallet;
